# Simple in-memory cache for high traffic scenarios
_cache = {}
CACHE_TTL = int(os.environ.get('CACHE_TTL', 30))  # 30 seconds default
CACHE_MAX_SIZE = int(os.environ.get('CACHE_MAX_SIZE', 10000))


def get_cached(key):
    """Get value from cache if not expired."""
    if key in _cache:
        value, timestamp = _cache[key]
        if time.time() - timestamp < CACHE_TTL:
            return value
        else:
            del _cache[key]
    return None


def set_cached(key, value):
    """Set value in cache with TTL, evict old entries if cache is full."""
    if len(_cache) >= CACHE_MAX_SIZE:
        # Evict expired entries first
        now = time.time()
        expired_keys = [k for k, (v, t) in _cache.items() if now - t >= CACHE_TTL]
        for k in expired_keys:
            del _cache[k]
        # If still full, evict oldest entries
        if len(_cache) >= CACHE_MAX_SIZE:
            oldest_keys = sorted(_cache.keys(), key=lambda k: _cache[k][1])[:CACHE_MAX_SIZE // 4]
            for k in oldest_keys:
                del _cache[k]
    _cache[key] = (value, time.time())


def rate_limit(max_requests_per_minute=600):
    """Simple rate limiting decorator based on IP address."""
    request_log = {}

    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            ip = request.remote_addr
            now = time.time()

            # Clean old entries
            if ip in request_log:
                request_log[ip] = [t for t in request_log[ip] if now - t < 60]

            if ip not in request_log:
                request_log[ip] = []

            if len(request_log[ip]) >= max_requests_per_minute:
                return jsonify({
                    'error': 'Rate limit exceeded',
                    'message': f'Maximum {max_requests_per_minute} requests per minute allowed'
                }), 429

            request_log[ip].append(now)
            return f(*args, **kwargs)
        return wrapper
    return decorator


def build_search_query(keyword, category=None, min_price=None, max_price=None,
                       sort_by=None, sort_order='desc'):
    """Build Elasticsearch query with optional filters."""
    must_clauses = []
    filter_clauses = []

    # Main keyword search across multiple fields with boosting
    if keyword:
        must_clauses.append({
            'multi_match': {
                'query': keyword,
                'fields': [
                    'name^3',          # Product name gets highest boost
                    'name.autocomplete^2',
                    'description^1.5',
                    'brand^2',
                    'category^1',
                    'tags^1',
                    'sku^4'            # Exact SKU match gets very high boost
                ],
                'type': 'best_fields',
                'fuzziness': 'AUTO',
                'prefix_length': 2,
                'minimum_should_match': '75%'
            }
        })

    # Category filter
    if category:
        filter_clauses.append({
            'term': {'category.keyword': category}
        })

    # Price range filter
    if min_price is not None or max_price is not None:
        price_range = {}
        if min_price is not None:
            price_range['gte'] = float(min_price)
        if max_price is not None:
            price_range['lte'] = float(max_price)
        filter_clauses.append({
            'range': {'price': price_range}
        })

    # Only show active/available products
    filter_clauses.append({
        'term': {'is_active': True}
    })

    query = {
        'bool': {
            'must': must_clauses if must_clauses else [{'match_all': {}}],
            'filter': filter_clauses
        }
    }

    # Build the full search body
    body = {
        'query': query,
        'highlight': {
            'fields': {
                'name': {'number_of_fragments': 1},
                'description': {'number_of_fragments': 2, 'fragment_size': 150}
            },
            'pre_tags': ['<em>'],
            'post_tags': ['</em>']
        },
        'aggs': {
            'categories': {
                'terms': {
                    'field': 'category.keyword',
                    'size': 20
                }
            },
            'brands': {
                'terms': {
                    'field': 'brand.keyword',
                    'size': 20
                }
            },
            'price_ranges': {
                'range': {
                    'field': 'price',
                    'ranges': [
                        {'to': 25, 'key': 'under_25'},
                        {'from': 25, 'to': 50, 'key': '25_to_50'},
                        {'from': 50, 'to': 100, 'key': '50_to_100'},
                        {'from': 100, 'to': 200, 'key': '100_to_200'},
                        {'from': 200, 'key': 'over_200'}
                    ]
                }
            },
            'avg_price': {
                'avg': {'field': 'price'}
            }
        },
        'suggest': {
            'product_suggest': {
                'text': keyword or '',
                'term': {
                    'field': 'name',
                    'suggest_mode': 'popular',
                    'min_word_length': 3
                }
            }
        }
    }

    # Sorting
    if sort_by:
        sort_mapping = {
            'price': 'price',
            'name': 'name.keyword',
            'rating': 'rating',
            'created': 'created_at',
            'popularity': 'sales_count'
        }
        sort_field = sort_mapping.get(sort_by, 'price')
        body['sort'] = [
            {sort_field: {'order': sort_order}},
            '_score'
        ]

    return body


def format_search_results(response, page, size):
    """Format Elasticsearch response into a clean API response."""
    hits = response.get('hits', {})
    total = hits.get('total', {})
    total_count = total.get('value', 0) if isinstance(total, dict) else total

    products = []
    for hit in hits.get('hits', []):
        source = hit.get('_source', {})
        product = {
            'id': hit.get('_id'),
            'score': hit.get('_score'),
            'name': source.get('name'),
            'description': source.get('description'),
            'price': source.get('price'),
            'currency': source.get('currency', 'USD'),
            'brand': source.get('brand'),
            'category': source.get('category'),
            'image_url': source.get('image_url'),
            'rating': source.get('rating'),
            'review_count': source.get('review_count'),
            'in_stock': source.get('in_stock', True),
            'sku': source.get('sku'),
            'tags': source.get('tags', []),
        }

        # Add highlights if available
        highlights = hit.get('highlight', {})
        if highlights:
            product['highlights'] = {
                field: fragments
                for field, fragments in highlights.items()
            }

        products.append(product)

    # Format aggregations
    aggs = response.get('aggregations', {})
    facets = {}

    if 'categories' in aggs:
        facets['categories'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggs['categories'].get('buckets', [])
        ]

    if 'brands' in aggs:
        facets['brands'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggs['brands'].get('buckets', [])
        ]

    if 'price_ranges' in aggs:
        facets['price_ranges'] = [
            {
                'key': bucket['key'],
                'count': bucket['doc_count'],
                'from': bucket.get('from'),
                'to': bucket.get('to')
            }
            for bucket in aggs['price_ranges'].get('buckets', [])
        ]

    if 'avg_price' in aggs:
        facets['avg_price'] = round(aggs['avg_price'].get('value', 0), 2) if aggs['avg_price'].get('value') else None

    # Format suggestions
    suggestions = []
    suggest = response.get('suggest', {})
    for suggestion_group in suggest.get('product_suggest', []):
        for option in suggestion_group.get('options', []):
            suggestions.append(option.get('text'))

    total_pages = (total_count + size - 1) // size if size > 0 else 0

    return {
        'results': products,
        'pagination': {
            'total': total_count,
            'page': page,
            'size': size,
            'total_pages': total_pages,
            'has_next': page < total_pages,
            'has_prev': page > 1
        },
        'facets': facets,
        'suggestions': suggestions
    }


@app.route('/api/search', methods=['GET'])
@rate_limit(max_requests_per_minute=600)
def search_products():
    """
    Search products by keyword with optional filters.

    Query Parameters:
        q (str): Search keyword (required)
        category (str): Filter by category
        min_price (float): Minimum price filter
        max_price (float): Maximum price filter
        sort_by (str): Sort field (price, name, rating, created, popularity)
        sort_order (str): Sort order (asc, desc) - default: desc
        page (int): Page number (default: 1)
        size (int): Results per page (default: 20, max: 100)

    Returns:
        JSON with results, pagination, facets, and suggestions
    """
    start_time = time.time()

    # Parse query parameters
    keyword = request.args.get('q', '').strip()
    category = request.args.get('category', None)
    min_price = request.args.get('min_price', None)
    max_price = request.args.get('max_price', None)
    sort_by = request.args.get('sort_by', None)
    sort_order = request.args.get('sort_order', 'desc')
    page = request.args.get('page', 1, type=int)
    size = request.args.get('size', 20, type=int)

    # Validate parameters
    if not keyword:
        return jsonify({
            'error': 'Bad Request',
            'message': 'Query parameter "q" is required'
        }), 400

    if len(keyword) > 200:
        return jsonify({
            'error': 'Bad Request',
            'message': 'Query parameter "q" must be 200 characters or fewer'
        }), 400

    if page < 1:
        page = 1
    if size < 1:
        size = 1
    if size > 100:
        size = 100

    if sort_order not in ('asc', 'desc'):
        sort_order = 'desc'

    if sort_by and sort_by not in ('price', 'name', 'rating', 'created', 'popularity'):
        return jsonify({
            'error': 'Bad Request',
            'message': 'Invalid sort_by value. Must be one of: price, name, rating, created, popularity'
        }), 400

    # Validate price parameters
    try:
        if min_price is not None:
            min_price = float(min_price)
            if min_price < 0:
                return jsonify({'error': 'Bad Request', 'message': 'min_price must be non-negative'}), 400
        if max_price is not None:
            max_price = float(max_price)
            if max_price < 0:
                return jsonify({'error': 'Bad Request', 'message': 'max_price must be non-negative'}), 400
        if min_price is not None and max_price is not None and min_price > max_price:
            return jsonify({'error': 'Bad Request', 'message': 'min_price must be less than or equal to max_price'}), 400
    except (ValueError, TypeError):
        return jsonify({'error': 'Bad Request', 'message': 'Invalid price parameter'}), 400

    # Build cache key
    cache_key = f"{keyword}:{category}:{min_price}:{max_price}:{sort_by}:{sort_order}:{page}:{size}"

    # Check cache
    cached_result = get_cached(cache_key)
    if cached_result is not None:
        elapsed = time.time() - start_time
        cached_result['meta'] = {
            'took_ms': round(elapsed * 1000, 2),
            'cached': True
        }
        logger.info(f"Cache hit for query='{keyword}' - {elapsed*1000:.2f}ms")
        return jsonify(cached_result), 200

    # Build and execute search query
    try:
        search_body = build_search_query(
            keyword=keyword,
            category=category,
            min_price=min_price,
            max_price=max_price,
            sort_by=sort_by,
            sort_order=sort_order
        )

        # Calculate offset
        from_offset = (page - 1) * size

        response = es.search(
            index=ES_INDEX,
            body=search_body,
            from_=from_offset,
            size=size,
            request_timeout=5  # Aggressive timeout for search requests
        )

        # Format results
        result = format_search_results(response, page, size)

        elapsed = time.time() - start_time
        es_took = response.get('took', 0)

        result['meta'] = {
            'took_ms': round(elapsed * 1000, 2),
            'es_took_ms': es_took,
            'cached': False
        }

        # Cache the result
        set_cached(cache_key, result)

        logger.info(
            f"Search query='{keyword}' category={category} page={page} "
            f"total={result['pagination']['total']} "
            f"took={elapsed*1000:.2f}ms es_took={es_took}ms"
        )

        return jsonify(result), 200

    except Exception as e:
        elapsed = time.time() - start_time
        logger.error(f"Search error for query='{keyword}': {str(e)} - {elapsed*1000:.2f}ms")

        # Check if it's a connection error
        error_type = type(e).__name__
        if 'ConnectionError' in error_type or 'ConnectionTimeout' in error_type:
            return jsonify({
                'error': 'Service Unavailable',
                'message': 'Search service is temporarily unavailable. Please try again later.'
            }), 503

        if 'RequestError' in error_type:
            return jsonify({
                'error': 'Bad Request',
                'message': 'Invalid search query'
            }), 400

        return jsonify({
            'error': 'Internal Server Error',
            'message': 'An unexpected error occurred while processing your search'
        }), 500


@app.route('/api/search/suggest', methods=['GET'])
@rate_limit(max_requests_per_minute=1200)
def search_suggest():
    """
    Autocomplete/suggest endpoint for search-as-you-type functionality.

    Query Parameters:
        q (str): Partial search term (required)
        size (int): Number of suggestions (default: 5, max: 10)
    """
    keyword = request.args.get('q', '').strip()
    size = request.args.get('size', 5, type=int)

    if not keyword or len(keyword) < 2:
        return jsonify({'suggestions': []}), 200

    if size < 1:
        size = 1
    if size > 10:
        size = 10

    # Check cache
    cache_key = f"suggest:{keyword}:{size}"
    cached = get_cached(cache_key)
    if cached is not None:
        return jsonify(cached), 200

    try:
        body = {
            'size': 0,
            'suggest': {
                'product_suggest': {
                    'prefix': keyword,
                    'completion': {
                        'field': 'name.suggest',
                        'size': size,
                        'skip_duplicates': True,
                        'fuzzy': {
                            'fuzziness': 'AUTO'
                        }
                    }
                }
            }
        }

        response = es.search(
            index=ES_INDEX,
            body=body,
            request_timeout=3
        )

        suggestions = []
        suggest = response.get('suggest', {})
        for suggestion_group in suggest.get('product_suggest', []):
            for option in suggestion_group.get('options', []):
                source = option.get('_source', {})
                suggestions.append({
                    'text': option.get('text'),
                    'id': option.get('_id'),
                    'category': source.get('category'),
                    'price': source.get('price')
                })

        result = {'suggestions': suggestions}
        set_cached(cache_key, result)

        return jsonify(result), 200

    except Exception as e:
        logger.error(f"Suggest error for query='{keyword}': {str(e)}")
        return jsonify({'suggestions': []}), 200  # Graceful degradation


@app.route('/api/health', methods=['GET'])
def health_check():
    """Health check endpoint for load balancers."""
    try:
        es_health = es.cluster.health(request_timeout=3)
        es_status = es_health.get('status', 'unknown')
        es_healthy = es_status in ('green', 'yellow')

        return jsonify({
            'status': 'healthy' if es_healthy else 'degraded',
            'elasticsearch': {
                'status': es_status,
                'cluster_name': es_health.get('cluster_name'),
                'number_of_nodes': es_health.get('number_of_nodes')
            },
            'cache_size': len(_cache)
        }), 200 if es_healthy else 503

    except Exception as e:
        logger.error(f"Health check failed: {str(e)}")
        return jsonify({
            'status': 'unhealthy',
            'error': str(e)
        }), 503


@app.route('/api/cache/clear', methods=['POST'])
def clear_cache():
    """Clear the search cache. Useful after product updates."""
    global _cache
    cache_size = len(_cache)
    _cache = {}
    logger.info(f"Cache cleared: {cache_size} entries removed")
    return jsonify({
        'message': 'Cache cleared',
        'entries_removed': cache_size
    }), 200


def create_index_mapping():
    """Create the Elasticsearch index with proper mappings for product search."""
    mapping = {
        'settings': {
            'number_of_shards': 3,
            'number_of_replicas': 1,
            'analysis': {
                'analyzer': {
                    'autocomplete_analyzer': {
                        'type': 'custom',
                        'tokenizer': 'autocomplete_tokenizer',
                        'filter': ['lowercase', 'asciifolding']
                    },
                    'search_analyzer': {
                        'type': 'custom',
                        'tokenizer': 'standard',
                        'filter': ['lowercase', 'asciifolding']
                    }
                },
                'tokenizer': {
                    'autocomplete_tokenizer': {
                        'type': 'edge_ngram',
                        'min_gram': 2,
                        'max_gram': 20,
                        'token_chars': ['letter', 'digit']
                    }
                }
            }
        },
        'mappings': {
            'properties': {
                'name': {
                    'type': 'text',
                    'analyzer': 'standard',
                    'fields': {
                        'keyword': {'type': 'keyword'},
                        'autocomplete': {
                            'type': 'text',
                            'analyzer': 'autocomplete_analyzer',
                            'search_analyzer': 'search_analyzer'
                        },
                        'suggest': {
                            'type': 'completion'
                        }
                    }
                },
                'description': {
                    'type': 'text',
                    'analyzer': 'standard'
                },
                'price': {'type': 'float'},
                'currency': {'type': 'keyword'},
                'brand': {
                    'type': 'text',
                    'fields': {
                        'keyword': {'type': 'keyword'}
                    }
                },
                'category': {
                    'type': 'text',
                    'fields': {
                        'keyword': {'type': 'keyword'}
                    }
                },
                'tags': {'type': 'keyword'},
                'sku': {'type': 'keyword'},
                'image_url': {'type': 'keyword', 'index': False},
                'rating': {'type': 'float'},
                'review_count': {'type': 'integer'},
                'sales_count': {'type': 'integer'},
                'in_stock': {'type': 'boolean'},
                'is_active': {'type': 'boolean'},
                'created_at': {'type': 'date'},
                'updated_at': {'type': 'date'}
            }
        }
    }

    if not es.indices.exists(index=ES_INDEX):
        es.indices.create(index=ES_INDEX, body=mapping)
        logger.info(f"Created index '{ES_INDEX}' with mappings")
    else:
        logger.info(f"Index '{ES_INDEX}' already exists")


